SafetyState safety=SafetyState::BOOT; TestProfile profile=TestProfile::None; bool tofReady=false,inaReady=false,pcaReady=false,navOriginSet=false; uint32_t bootId=0,lastInaUs=0,lastTofUs=0,lastVescReqMs=0,lastDutyMs=0,testStartMs=0,lastDiagMs=0,lastHostHeartbeatMs=0,lastControlHeartbeatMs=0,lastNavSequence=0,navSequenceGaps=0,navCrcErrors=0; int32_t navOriginLatE7=0,navOriginLonE7=0; uint16_t servoTarget=kServoCenterUs,servoOutput=kServoCenterUs; uint32_t tofFrames=0,vescReq=0,vescResp=0,vescErrors=0,linkSeq=0,linkDrops=0,linkQueueHighWater=0,linkRxFrames=0,linkStopCommands=0,linkEstopCommands=0,gnssNavRx=0,gnssResultTx=0; boat::Decoder linkDecoder; struct TxItem{uint16_t length=0,offset=0;uint8_t data[boat::kMaxEncoded]{};}; constexpr uint8_t kLinkQueueDepth=96; TxItem linkQueue[kLinkQueueDepth]{};uint8_t linkHead=0,linkTail=0,linkUsed=0;portMUX_TYPE linkMux=portMUX_INITIALIZER_UNLOCKED;
uint64_t nowUs(){return esp_timer_get_time();}
void linkSend(boat::Type type,const uint8_t*p,uint16_t n,uint16_t flags=0){uint8_t encoded[boat::kMaxEncoded];boat::Header h{boat::kVersion,(uint8_t)type,n,++linkSeq,bootId,nowUs(),flags};uint16_t length=(uint16_t)boat::encode(h,p,encoded,sizeof(encoded));if(!length){linkDrops++;return;}portENTER_CRITICAL(&linkMux);if(linkUsed>=kLinkQueueDepth){linkDrops++;portEXIT_CRITICAL(&linkMux);return;}TxItem&x=linkQueue[linkHead];x.offset=0;x.length=length;memcpy(x.data,encoded,length);linkHead=(linkHead+1)%kLinkQueueDepth;linkUsed++;if(linkUsed>linkQueueHighWater)linkQueueHighWater=linkUsed;portEXIT_CRITICAL(&linkMux);}
void linkService(){while(true){portENTER_CRITICAL(&linkMux);if(!linkUsed){portEXIT_CRITICAL(&linkMux);return;}TxItem*x=&linkQueue[linkTail];uint16_t offset=x->offset,length=x->length;portEXIT_CRITICAL(&linkMux);int room=linkUart.availableForWrite();if(room<=0)return;size_t remain=length-offset,want=remain<(size_t)room?remain:(size_t)room;size_t done=linkUart.write(x->data+offset,want);if(!done)return;portENTER_CRITICAL(&linkMux);x->offset+=done;if(x->offset>=x->length){linkTail=(linkTail+1)%kLinkQueueDepth;linkUsed--;}portEXIT_CRITICAL(&linkMux);}}
void linkTxTask(void*){for(;;){linkService();vTaskDelay(1);}}uint16_t crc16(const uint8_t*d,size_t n){return vesc::Parser::crc16(d,n);} void vescSend(const uint8_t*p,uint8_t n){uint16_t c=crc16(p,n);vescUart.write(2);vescUart.write(n);vescUart.write(p,n);vescUart.write(c>>8);vescUart.write(c);vescUart.write(3);} void vescDuty(float duty){if(kDryRunActuators&&duty!=0)return;int32_t x=(int32_t)(constrain(duty,-kVescMaxDuty,kVescMaxDuty)*100000.0f);uint8_t p[5]={5,(uint8_t)(x>>24),(uint8_t)(x>>16),(uint8_t)(x>>8),(uint8_t)x};vescSend(p,5);} void safeOutputs(){vescDuty(0);if(pcaReady)pca.allOff();servoOutput=kServoCenterUs;}
void setState(SafetyState n){if(n==safety)return;safety=n;Serial.printf("STATE %s\n",stateName(safety));}
void bnoEvent(const bno::Sample&s){struct __attribute__((packed)){uint8_t kind,accuracy,sequence;uint8_t reserved;uint64_t sensorUs;float v[7];} p{};p.kind=(uint8_t)s.type;p.accuracy=s.accuracy;p.sequence=s.sequence;p.sensorUs=s.sensorUs;memcpy(p.v,s.v,sizeof(p.v));linkSend(s.type==bno::EventType::Accel?boat::Type::BnoAccel:s.type==bno::EventType::Gyro?boat::Type::BnoGyro:boat::Type::BnoQuaternion,(uint8_t*)&p,sizeof(p));}
void scan(){char a[96]="";size_t used=0;for(uint8_t x=8;x<120;x++){Wire.beginTransmission(x);if(!Wire.endTransmission())used+=snprintf(a+used,sizeof(a)-used,"%s0x%02X",used?",":"",x);}Serial.printf("PERIPH_SCAN %s\n",used?a:"none");}
void pollTof(){if(!tofReady||!tof.isDataReady())return;uint64_t t=nowUs();if(!tof.getRangingData(&tofData))return;tofFrames++;lastTofUs=t;uint8_t p[196];memcpy(p,&tofFrames,4);memcpy(p+4,tofData.distance_mm,128);memcpy(p+132,tofData.target_status,64);linkSend(boat::Type::TofFrame,p,sizeof(p));}
void pollIna(){if((uint32_t)(nowUs()-lastInaUs)<kInaSampleUs)return;lastInaUs=nowUs();InaSample s{};if(inaReady)ina.read(s);if(s.valid){struct __attribute__((packed)){int16_t shunt,current;uint16_t bus,power,mask;uint32_t i2cUs;} p{s.rawShunt,s.rawCurrent,s.rawBus,s.rawPower,s.mask,s.i2cUs};linkSend(boat::Type::InaSample,(uint8_t*)&p,sizeof(p));}if(s.valid&&kEnableOverCurrentTrip&&fabsf(s.currentRegA)>kOverCurrentTripA){safeOutputs();setState(SafetyState::FAULT);}}
void pollVesc(){while(vescUart.available()){vesc::Frame f{};vesc::ParseError e; if(vescParser.feed((uint8_t)vescUart.read(),nowUs(),f,e)){if(f.crcOk&&f.endOk&&vesc::Parser::parseCurrentValues(f,vescValues)){vescResp++;linkSend(boat::Type::VescStatus,(uint8_t*)&vescValues,sizeof(vescValues));}else vescErrors++;}}if(millis()-lastVescReqMs>=kVescRequestIntervalMs){lastVescReqMs=millis();uint8_t p=4;vescSend(&p,1);vescReq++;}}
void stop();
void sendCommandAck(const boat::Frame&f,uint8_t disposition,uint16_t reason){boat::CommandPayload c{};if(f.header.length==sizeof(c))memcpy(&c,f.payload,sizeof(c));boat::CommandAckPayload ack{c.commandId,c.commandType,disposition,(uint8_t)safety,(uint8_t)kDryRunActuators,nowUs(),nowUs(),reason,0};linkSend(boat::Type::CommandAck,(uint8_t*)&ack,sizeof(ack));}
void processNav(const boat::Frame&f){boat::GnssNavPayload nav{};if(f.header.length!=sizeof(nav)){navCrcErrors++;return;}memcpy(&nav,f.payload,sizeof(nav));uint32_t flags=0;if(nav.canonicalCrc!=boat::canonicalCrc(&nav,offsetof(boat::GnssNavPayload,canonicalCrc))){navCrcErrors++;flags|=8;}bool duplicate=lastNavSequence&&nav.navSequence==lastNavSequence;if(duplicate)flags|=2;if(lastNavSequence&&nav.navSequence!=lastNavSequence+1&&!duplicate){flags|=4;navSequenceGaps++;}lastNavSequence=nav.navSequence;if((nav.flags&boat::NavFixValid)&&!navOriginSet){navOriginSet=true;navOriginLatE7=nav.latitudeE7;navOriginLonE7=nav.longitudeE7;}boat::GnssProcessResultPayload r{};r.navSequence=nav.navSequence;r.fixSequence=nav.fixSequence;r.navCanonicalCrc=nav.canonicalCrc;r.flags=flags;r.controlReceivedUs=nowUs();r.originLatitudeE7=navOriginLatE7;r.originLongitudeE7=navOriginLonE7;r.speedMmPerSec=nav.speedMmPerSec;r.courseMilliRad=(int32_t)lround((nav.courseE5Deg/100000.0)*PI/180.0*1000.0);if(navOriginSet){r.flags|=16;r.northMm=(int32_t)lround((nav.latitudeE7-navOriginLatE7)*11.132);r.eastMm=(int32_t)lround((nav.longitudeE7-navOriginLonE7)*11.132*cos(navOriginLatE7/1e7*PI/180.0));}if((nav.flags&boat::NavFixValid)&&!(flags&8))r.flags|=1;r.errorCode=(flags&8)?1:0;r.safetyState=(uint16_t)safety;r.dryRun=kDryRunActuators;r.controlSentUs=nowUs();r.canonicalCrc=boat::canonicalCrc(&r,offsetof(boat::GnssProcessResultPayload,canonicalCrc));linkSend(boat::Type::GnssProcessResult,(uint8_t*)&r,sizeof(r));gnssResultTx++;}
void linkRxService(){while(linkUart.available()){boat::Frame f{};if(!linkDecoder.feed((uint8_t)linkUart.read(),f))continue;++linkRxFrames;boat::Type type=(boat::Type)f.header.type;if(type==boat::Type::Heartbeat){lastHostHeartbeatMs=millis();}else if(type==boat::Type::GnssNav){gnssNavRx++;processNav(f);}else if(type==boat::Type::TimeSyncRequest&&f.header.length==sizeof(boat::TimeSyncRequestPayload)){boat::TimeSyncRequestPayload q{};memcpy(&q,f.payload,sizeof(q));boat::TimeSyncReplyPayload a{q.sequence,q.t1Us,nowUs(),nowUs()};linkSend(boat::Type::TimeSyncReply,(uint8_t*)&a,sizeof(a));}else if(type==boat::Type::Stop){++linkStopCommands;stop();sendCommandAck(f,0,0);}else if(type==boat::Type::Estop){++linkEstopCommands;safeOutputs();profile=TestProfile::None;setState(SafetyState::E_STOP);sendCommandAck(f,0,0);}else if(type==boat::Type::ClearEstop){if(safety==SafetyState::E_STOP)setState(SafetyState::DISARMED);sendCommandAck(f,0,0);}}}
