void start(TestProfile p){if(safety!=SafetyState::ARMED_IDLE)return;profile=p;testStartMs=millis();setState(SafetyState::RUNNING);} void stop(){safeOutputs();profile=TestProfile::None;if(safety!=SafetyState::E_STOP)setState(SafetyState::DISARMED);} void command(const char*c){if(!strcmp(c,"help"))Serial.println("help status scan arm disarm stop estop clear_estop sensors_start sensors_stop servo_center servo_slow_test vesc_status_test vesc_3percent_test diag_on diag_off");else if(!strcmp(c,"status"))Serial.printf("%s BNO=%d TOF=%d INA=%d PCA=%d VESC=%lu/%lu\n",stateName(safety),imu.ready(),tofReady,inaReady,pcaReady,vescResp,vescReq);else if(!strcmp(c,"scan"))scan();else if(!strcmp(c,"arm")&&safety==SafetyState::DISARMED)setState(SafetyState::ARMED_IDLE);else if(!strcmp(c,"disarm")||!strcmp(c,"stop"))stop();else if(!strcmp(c,"estop")){safeOutputs();setState(SafetyState::E_STOP);}else if(!strcmp(c,"clear_estop")&&safety==SafetyState::E_STOP)setState(SafetyState::DISARMED);else if(!strcmp(c,"sensors_start"))start(TestProfile::SensorOnly);else if(!strcmp(c,"servo_center"))start(TestProfile::ServoCenter);else if(!strcmp(c,"servo_slow_test"))start(TestProfile::ServoSlow);else if(!strcmp(c,"vesc_status_test"))start(TestProfile::VescStatus);else if(!strcmp(c,"vesc_3percent_test"))start(TestProfile::VescDuty);}
